INSERT INTO pet_tips (title, category, content, cover_image, create_time, update_time, deleted) VALUES
('幼犬营养指南', '饮食', '<h2>幼犬营养指南</h2><p>幼犬正处于快速生长发育阶段，需要均衡的营养来支持健康成长。以下是幼犬营养的关键要点：</p><h3>1. 蛋白质需求</h3><p>幼犬需要高质量的蛋白质来支持肌肉和组织生长。优质蛋白质来源包括鸡肉、鱼肉、牛肉和蛋类。</p><h3>2. 适量脂肪</h3><p>健康的脂肪能提供幼犬所需的能量，同时有助于皮肤和毛发健康。鱼油和植物油都是不错的选择。</p><h3>3. 维生素和矿物质</h3><p>确保幼犬获得足够的钙、磷、维生素D等营养素，以支持骨骼和牙齿发育。</p><h3>4. 定时定量喂食</h3><p>建议每天3-4次定时定量喂食，避免过度喂养导致肥胖问题。</p><h3>5. 选择优质狗粮</h3><p>请选择专为幼犬设计的优质狗粮，并根据幼犬年龄和体重调整喂食量。</p>', NULL, '2023-10-12 10:00:00', '2023-10-12 10:00:00', 0),
('如何与救助宠物建立信任', '行为', '<h2>如何与救助宠物建立信任</h2><p>救助宠物往往经历过流浪或被遗弃的创伤，需要更多耐心和关爱才能建立信任关系。</p><h3>1. 给它们空间</h3><p>刚到家的救助宠物需要时间适应新环境。不要强迫互动，让它们自己探索新家。</p><h3>2. 建立日常规律</h3><p>固定的喂食时间、玩耍时间和休息时间能让宠物感到安全，帮助它们更快适应。</p><h3>3. 使用温和的声音</h3><p>与救助宠物交流时使用温和、平静的语调，避免突然的大声或动作惊吓到它们。</p><h3>4. 食物是最好的纽带</h3><p>亲手喂食零食可以快速建立亲密感。让它们将你与美味和美好体验联系在一起。</p><h3>5. 耐心是关键</h3><p>建立信任可能需要几天、几周甚至几个月的时间。不要着急，让关系自然发展。</p>', NULL, '2023-09-28 14:30:00', '2023-09-28 14:30:00', 0),
('家庭美容要点', '健康', '<h2>家庭美容要点</h2><p>定期美容不仅能让宠物看起来整洁，还能促进皮肤健康，及时发现潜在健康问题。</p><h3>1. 梳毛频率</h3><p>根据宠物毛发类型确定梳毛频率：短毛猫犬每周1-2次，长毛猫犬可能需要每天梳理。</p><h3>2. 洗澡技巧</h3><p>使用宠物专用沐浴露，水温适中，避免水进入耳朵和眼睛。洗澡不宜过频，一般每月1-2次。</p><h3>3. 指甲修剪</h3><p>定期检查和修剪指甲，过长的指甲会导致行走不适甚至关节问题。</p><h3>4. 耳朵清洁</h3><p>每周检查耳朵，使用宠物专用清洁液轻轻擦拭外耳，避免深入耳道。</p><h3>5. 牙齿护理</h3><p>每天刷牙是最好的牙齿护理方式，也可以使用磨牙棒和洁牙产品辅助。</p>', NULL, '2023-09-15 09:15:00', '2023-09-15 09:15:00', 0),
('为猫咪创建安全的室内空间', '环境', '<h2>为猫咪创建安全的室内空间</h2><p>室内生活的猫咪需要一个安全、丰富且能满足其自然行为需求的环境。</p><h3>1. 提供垂直空间</h3><p>猫咪喜欢爬高，提供猫爬架、窗台平台等垂直空间能让它们感到安全。</p><h3>2. 隐藏和休息区</h3><p>准备纸箱、猫窝或隐蔽空间，让猫咪有地方可以躲藏和安心休息。</p><h3>3. 磨爪设施</h3><p>提供猫抓板或猫抓柱，满足猫咪磨爪的自然需求，保护家具。</p><h3>4. 安全隐患排查</h3><p>收好电线、有毒植物、小物件等潜在危险，确保猫咪无法接触到。</p><h3>5. 丰富的玩具</h3><p>提供各种类型的玩具，定期轮换，保持猫咪的好奇心和活动量。</p>', NULL, '2023-08-22 16:45:00', '2023-08-22 16:45:00', 0),
('了解狗狗的肢体语言', '行为', '<h2>了解狗狗的肢体语言</h2><p>学会解读狗狗的肢体语言能帮助你更好地理解它们的情绪和需求。</p><h3>1. 尾巴姿态</h3><p>尾巴高高竖起表示兴奋或自信；夹在腿间表示害怕或不安；缓慢摇摆表示放松。</p><h3>2. 耳朵位置</h3><p>耳朵竖起表示警觉；耳朵向后贴表示害怕或顺从；耳朵放松自然表示舒适。</p><h3>3. 眼神交流</h3><p>温柔的眼神表示信任；避开视线可能表示不安或服从；凝视可能是警告信号。</p><h3>4. 身体姿态</h3><p>身体放松、重心稳定表示舒适；身体紧绷、毛发竖起可能表示紧张或准备攻击。</p><h3>5. 舔舐行为</h3><p>舔鼻子可能表示压力；舔你表示 affection；频繁舔自己可能表示焦虑或皮肤问题。</p>', NULL, '2023-08-10 11:20:00', '2023-08-10 11:20:00', 0),
('疫苗接种时间表解读', '健康', '<h2>疫苗接种时间表解读</h2><p>按时接种疫苗是保护宠物免受严重传染病侵害的关键措施。</p><h3>1. 幼犬/幼猫基础免疫</h3><p>通常在6-8周龄开始第一针，之后每3-4周加强一次，直到16周龄左右。</p><h3>2. 核心疫苗</h3><p>犬：犬瘟热、细小病毒、腺病毒、副流感；猫：猫瘟、猫疱疹病毒、猫杯状病毒。</p><h3>3. 非核心疫苗</h3><p>根据生活环境和风险评估选择，如犬钩端螺旋体、猫白血病等。</p><h3>4. 成年后加强</h3><p>一般每年或每三年加强一次，具体根据疫苗类型和兽医建议。</p><h3>5. 接种注意事项</h3><p>接种前确保宠物健康；接种后观察30分钟；记录接种时间和疫苗类型。</p>', NULL, '2023-07-05 08:30:00', '2023-07-05 08:30:00', 0);
